    assert_eq!(location, "/todos", "Should redirect back to /todos");

    // Verify it's gone
    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to get todos page");
    let body = response.text().await.unwrap();

